import { Logger } from './Logger';
 
export interface EventPayload {
    type: string;        // Formato: NAMESPACE:ACTION
    entityId?: number;
    timestamp: number;
    data: Record<string, any>;
}
 
export type TacticalHandler = (payload: EventPayload) => void;
 
class EventBus {
    private handlers: Map<string, TacticalHandler[]> = new Map();
 
    /**
     * Subscreve um manipulador. O eventType deve ser NAMESPACE:ACTION.
     * Retorna uma função de limpeza (unsubscribe).
     */
    public subscribe(eventType: string, handler: TacticalHandler): () => void {
        const type = eventType.toUpperCase();
        if (!this.handlers.has(type)) {
            this.handlers.set(type, []);
        }
        this.handlers.get(type)!.push(handler);

        // Retorna a função de limpeza
        return () => {
            const currentHandlers = this.handlers.get(type);
            if (currentHandlers) {
                this.handlers.set(type, currentHandlers.filter(h => h !== handler));
            }
        };
    }
 
    /**
     * Emite um evento. Suporta payload único ou (tipo, dados).
     */
    public emit(typeOrPayload: string | EventPayload, data?: any): void {
        let payload: EventPayload;

        if (typeof typeOrPayload === 'string') {
            payload = {
                type: typeOrPayload,
                timestamp: data?.timestamp || Date.now(),
                data: data?.data ? data.data : (data || {})
            };
        } else {
            payload = typeOrPayload;
        }

        const type = payload.type.toUpperCase();
        
        // Registo Táctico (Controlado por DEBUG_MODE)
        Logger.event(type, payload);
 
        // Validação estrita em runtime (MEA Protocol)
        if (!type || !payload.timestamp || !payload.data) {
            console.error('[EVENT_BUS_FAILURE] Invalid payload rejected.', payload);
            return;
        }
 
        const callbacks = this.handlers.get(type);
        if (!callbacks || callbacks.length === 0) {
            // Disabled to avoid blocking the console due to highly emitted inputs:
            // console.warn(`[EVENT_BUS_WARNING] Event [${type}] has ZERO subscribers! Dead signal detected.`);
        }

        if (callbacks) {
            callbacks.forEach(cb => cb(payload));
        }
    }

    /**
     * Retorna informação sobre os handlers registados (para auditoria de integridade).
     */
    public getHandlersInfo(): Map<string, number> {
        const info = new Map<string, number>();
        this.handlers.forEach((handlers, type) => {
            info.set(type, handlers.length);
        });
        return info;
    }
}
 
export const eventBus = new EventBus();
 
